&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;महादेव जी की खूबियों को पहचानना&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;गाँधी जी ने&amp;nbsp;&lt;/span&gt;&lt;u style=&quot;&quot;&gt;उनको तत्काल पहचान लिया&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&amp;#39; वाक्य का तात्पर्य, &amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;महादेव जी की खूबियों को पहचानना&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;से&amp;nbsp;है&lt;/span&gt;।&lt;/li&gt;
	&lt;li&gt;गद्यांश&amp;nbsp;की&amp;nbsp;पंक्ति, &amp;quot;&lt;span style=&quot;&quot;&gt;गाँधी जी के लिए वे पुत्र से भी अधिक थे। जब सन्&amp;zwnj; 1917 में वे गाँधी जी के पास&amp;nbsp;पहुँचे थे, तभी गाँधी जी ने उनको &lt;strong&gt;तत्काल पहचान लिया&lt;/strong&gt; और उनको अपने&amp;nbsp;उत्तराधिकारी का पद सौंपा दिया।&lt;/span&gt;&amp;quot;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;तत्काल &lt;/strong&gt;का संधि विच्छेद:&amp;nbsp;&lt;strong&gt;तत् + काल&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसमें &lt;strong&gt;&amp;#39;व्यंजन संधि&amp;#39;&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उत्तराधिकारी&lt;/strong&gt; का अर्थ - किसी की मृत्यु के बाद उसकी संपत्ति पाने का अधिकारी, वारिस या किसी के बाद पद या अधिकार पानेवाला।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;पुत्र&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;उपरोक्त&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;गद्यांश&amp;nbsp;&lt;/span&gt;के अनुसार,&amp;nbsp;&lt;span style=&quot;&quot;&gt;महादेव&amp;nbsp;जी स्वयं के परिचय में &lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;पुत्र&lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;शब्द का प्रयोग नहीं करते थे&lt;/span&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;गद्यांश&amp;nbsp;की&amp;nbsp;पंक्ति, &amp;quot;मित्रों के बीच विनोद में अपने को गाँधी जी&amp;nbsp;का &amp;#39;&lt;strong&gt;हम्माल&lt;/strong&gt;&amp;#39; कहने में और कभी-कभी अपना परिचय उनके &amp;#39;पीर-&lt;strong&gt;बावर्ची-भिश्ती&lt;/strong&gt;-खर&amp;#39; के रूप में देने में, वे गौरव का अनुभव किया करते थे।&amp;quot;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;पुत्र&amp;#39;&lt;/span&gt;&amp;nbsp;पुल्लिंग&amp;nbsp;शब्द है, इसका स्त्रीलिंग शब्द&amp;nbsp;&lt;strong&gt;&amp;#39;पुत्री&amp;#39; &lt;/strong&gt;होगा।&lt;/li&gt;
	&lt;li&gt;&lt;b&gt;भिश्ती का अर्थ:&lt;/b&gt; मशक से पानी ढोनेवाला व्यक्ति।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;1929 में&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt;&amp;#39;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;महादेव जी अपने कार्यों से अपनी पहचान&amp;nbsp;वर्ष&amp;nbsp;&amp;nbsp;&lt;strong&gt;&amp;#39;1917 में&amp;#39;&lt;/strong&gt; बना चुके थे।&amp;#39;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;गद्यांश&amp;nbsp;की&amp;nbsp;पंक्ति, &amp;quot;&lt;span style=&quot;&quot;&gt;गाँधी जी ने उसी समय महादेव भाई को अपना वारिस कहा था। &lt;strong&gt;सन्&amp;zwnj; 1929&lt;/strong&gt;&amp;nbsp;में महादेव भाई, देश के चारों कोनों में, समूचे देश के दुलारे बन चुके थे।&amp;nbsp;&lt;/span&gt;&amp;quot;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;वारिस&lt;/strong&gt; का पर्यायवाची:&amp;nbsp;युवराज, राजकुमार, शाहज़ादा, वली अहद&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;एक प्रकार की जेल&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;गद्यांश में &lt;strong&gt;&amp;#39;कालापानी&amp;#39;&lt;/strong&gt; &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;#39;एक प्रकार की जेल&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;गद्यांश&amp;nbsp;की&amp;nbsp;पंक्ति, &amp;quot;&lt;span style=&quot;&quot;&gt;इस बीच पंजाब में फौजी शासन के कारण जो कहर बरसाया गया था, उसका&amp;nbsp;ब्यौरा रोज़-रोज़ आने लगा। पंजाब के अधिकतर नेताओं को गिरफ्तार करके फौजी कानून के तहत उम्र कैद की सजाएँ देकर &lt;strong&gt;कालापानी&lt;/strong&gt; भेज दिया गया।&lt;/span&gt;&amp;quot;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;कालापानी&lt;/span&gt;: यह जेल अंडमान निकोबार द्वीप की राजधानी पोर्ट ब्लेयर में बनी हुई है।&lt;/li&gt;
	&lt;li&gt;यह अंग्रेजों द्वारा भारतीय स्वतंत्रता संग्राम के सेनानियों को कैद रखने के लिए बनाई गई थी, जो कि मुख्य भारत भूमि से हजारों किलोमीटर दूर स्थित थी, व सागर से भी हजार किलोमीटर दुर्गम मार्ग पड़ता था।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;काला पानी&lt;/strong&gt; के नाम से कुख्यात थी।&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर &lt;strong&gt;&amp;#39;संयोजक&amp;#39;&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;और&amp;#39; शब्द&lt;strong&gt; &amp;#39;संयोजक&amp;#39;&lt;/strong&gt; समुच्चय बोधक है।&lt;/li&gt;
	&lt;li&gt;दो शब्दों या वाक्यों को जोड़ने वाले संयोजक शब्द को &lt;strong&gt;समुच्चयबोधक अव्यय&lt;/strong&gt; कहते हैं।&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सयोंजक समानाधिकरण समुच्चयबोधक:&amp;nbsp;&lt;/span&gt;ऐसे शब्द जो दो या दो से अधिक वाक्यों को आपस में परस्पर जोड़ने का काम करते हैं, वे शब्द सयोंजक समानाधिकरण समुच्चयबोधक शब्द कहलाते हैं। जैसे: भी, व,&lt;strong&gt;और&lt;/strong&gt;, तथा, एवं आदि।&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;उदाहरण&lt;/strong&gt;: राम &lt;strong&gt;और &lt;/strong&gt;मोहन भाई है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;​&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;b&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt;अन्य&lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt; &lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt;विकल्पों&lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt; &lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt;का&lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt; &lt;/span&gt;&lt;span style=&quot; line-height: 115%; &quot;&gt;विश्लेषण:&lt;/span&gt;&lt;/b&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;विभाजक समानाधिकरण समुच्चयबोधक :&lt;/strong&gt;ऐसे शब्द जो दुसरे शब्दों, वाक्यों या वाक्यांशों में विभाजन प्रकट करते हैं, वे शब्द विभाजक समानाधिकरण समुच्चयबोधक कहलाते हैं।

	&lt;ul&gt;
		&lt;li&gt;जैसे: ताकि, या-या, चाहे-चाहे, क्या-क्या, न-न, न कि, नहीं तो, परन्तु, तो, या, चाहे, अथवा, अन्यथा, वा, मगर आदि।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण:&amp;nbsp;&lt;/span&gt;अभी से परिश्रम करना शुरू करो ताकि आखिरी तक तैयार हो जाओ।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विरोधसूचक समानाधिकरण समुच्चयबोधक &lt;/strong&gt;: ऐसे शब्द जो दो विरोधी कथन, वाक्य या उपवाक्यों को जोड़ने का काम करते हैं, ऐसे शब्द विरोधसूचक समानाधिकरण समुच्चयबोधक शब्द कहलाते हैं।
	&lt;ul&gt;
		&lt;li&gt;जैसे: वरन, पर, परन्तु, किन्तु, मगर, बल्कि, लेकिन आदि।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण:&amp;nbsp;&lt;/span&gt;कशिश ने बहुत कोशिश की परन्तु उसे बचा नहीं सकी।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;परिणामसूचक समानाधिकरण समुच्चयबोधक : &lt;/strong&gt;ऐसे शब्द जो दो उपवाक्यों को जोड़ते हैं एवं जोड़ने के बाद उन दोनों वाक्य का परिणाम का बोध कराते हैं, ऐसे शब्द परिनामसूचक समानाधिकरण समुच्चयबोधक शब्द कहलाते हैं।
	&lt;ul&gt;
		&lt;li&gt;जैसे: इस कारण, अत:, अतएव, फलत:, परिणाम स्वरूप, इसलिए, फलस्वरूप, अन्यथा, इसीलिए आदि।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण:&amp;nbsp;&lt;/span&gt;उसने सबसे हटकर काम किया परिणामस्वरूप उसे पहचान मिली।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
